import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, null);

        boolean result = format.isNullStringSet();
        assertFalse(result);
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set nullString to a non-null value
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        boolean result = format.isNullStringSet();
        assertTrue(result);
    }
}
